   202→    MUTABLE_CONSTRUCT_ON_FIRST_USE(VersionedFactoryMap);
   203→  }
   204→
   205→  static absl::flat_hash_map<std::string, std::string>& deprecatedFactoryNames() {
   206→    static auto* deprecated_factory_names = new absl::flat_hash_map<std::string, std::string>;
   207→    return *deprecated_factory_names;
   208→  }
   209→
