    97→/**
    98→ * FactoryCategoryRegistry registers factory registries by their
    99→ * declared category. The category is exposed by a static category()
   100→ * method on the factory base type.
   101→ *
   102→ * Only RegisterFactory instances are able to register factory registries.
   103→ */
   104→class FactoryCategoryRegistry : public BaseFactoryCategoryRegistry {
   105→public:
   106→  /**
   107→   * @return a read-only reference to the map of registered factory
   108→   * registries.
   109→   */
   110→  static const MapType& registeredFactories() { return factories(); }
   111→
   112→  /**
   113→   * @return whether the given category name is already registered.
   114→   */
   115→  static bool isRegistered(absl::string_view category) {
   116→    return factories().find(category) != factories().end();
   117→  }
   118→
   119→  static bool disableFactory(absl::string_view category, absl::string_view name) {
   120→    auto registry = factories().find(category);
   121→
   122→    if (registry != factories().end()) {
   123→      return registry->second->disableFactory(name);
   124→    }
   125→
   126→    return false;
   127→  }
   128→
   129→private:
   130→  // Allow RegisterFactory and the test helper InjectFactoryCategory to register a category, but
   131→  // no-one else. This enforces correct use of the registration machinery.
   132→  template <class T, class Base> friend class RegisterFactory;
   133→  template <class Base> friend class InjectFactoryCategory;
   134→
   135→  static void registerCategory(const std::string& category, FactoryRegistryProxy* factory_names) {
   136→    auto result = factories().emplace(std::make_pair(category, factory_names));
   137→    RELEASE_ASSERT(result.second == true,
   138→                   fmt::format("Double registration for category: '{}'", category));
   139→  }
   140→
   141→  static void deregisterCategoryForTest(const std::string& category) {
   142→    factories().erase(category);
   143→    RELEASE_ASSERT(factories().find(category) == factories().end(),
   144→                   fmt::format("Deregistration for category '{}' failed", category));
   145→  }
   146→};
