   624→    // in headers by inserting an empty data frame with end_stream set. The empty data frame is sent
   625→    // after the new metadata.
   626→    if ((*entry)->end_stream_ && new_metadata_added && !buffered_request_data_) {
   627→      Buffer::OwnedImpl empty_data("");
